import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        x = int(data[i])
        out.append(f"K{x%100:02d}")
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

